import { z } from 'zod';

// --- Core Entity Type ---
export interface Item {
  id: string;
  name: string;
  description?: string;
  status: 'active' | 'inactive' | 'pending';
  createdAt: string;
  updatedAt: string;
}

// --- Zod Schemas for Validation ---

// Base schema for an Item (used for creating/full validation)
export const ItemSchema = z.object({
  id: z.string().uuid("ID must be a valid UUID."),
  name: z.string().min(3, "Name must be at least 3 characters long."),
  description: z.string().optional(),
  status: z.enum(['active', 'inactive', 'pending'], {
    errorMap: () => ({ message: "Status must be 'active', 'inactive', or 'pending'." })
  }),
  createdAt: z.string().datetime("createdAt must be a valid ISO datetime string."),
  updatedAt: z.string().datetime("updatedAt must be a valid ISO datetime string."),
});

// Schema for a partial Item update (patch)
export const ItemPatchSchema = ItemSchema.partial();

// Schema for a single item in the bulk update request body
export const BulkUpdateItemRequestSchema = z.object({
  id: z.string().uuid("ID must be a valid UUID."),
  patch: ItemPatchSchema,
});

// Schema for the entire bulk update request body
export const BulkUpdateRequestSchema = z.array(BulkUpdateItemRequestSchema)
  .min(1, "Bulk update request must contain at least one item.")
  .max(100, "Bulk update request cannot contain more than 100 items."); // Sensible default limit

// --- Response Types ---

// Type for a single item's result in the bulk update response
export interface BulkUpdateResponseItem {
  id: string;
  status: 'success' | 'failure';
  message?: string; // Error message if status is 'failure'
  data?: Item;      // Updated item data if status is 'success'
}
