import { Item } from '../types';
import { v4 as uuid } from 'uuid';

// In-memory database simulation
const items: Item[] = [
  {
    id: uuid(),
    name: 'Task A',
    description: 'Description for Task A',
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: uuid(),
    name: 'Task B',
    description: 'Description for Task B',
    status: 'pending',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: uuid(),
    name: 'Task C',
    description: 'Description for Task C',
    status: 'inactive',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
];

// Simulate a database connection error for demonstration
let simulateDbError = false;

export const setSimulateDbError = (value: boolean) => {
  simulateDbError = value;
};

/**
 * Simulates a bulk update operation within a transaction.
 * It attempts to apply each patch. If an item is not found or a specific
 * update fails, it's reported as a failure for that item.
 * If a critical database error is simulated, the entire transaction fails.
 *
 * @param updates An array of objects containing id and patch for each item.
 * @returns A promise resolving to an array of results for each item.
 */
export const bulkUpdateItems = async (
  updates: Array<{ id: string; patch: Partial<Item> }>
): Promise<Array<{ id: string; status: 'success' | 'failure'; message?: string; data?: Item }>> => {
  if (simulateDbError) {
    console.error('Simulating a critical database error.');
    throw new Error('Database connection lost during transaction.');
  }

  const results: Array<{ id: string; status: 'success' | 'failure'; message?: string; data?: Item }> = [];
  const changesToApply: { index: number; updatedItem: Item }[] = [];

  // Phase 1: Validate and prepare updates
  for (let i = 0; i < updates.length; i++) {
    const { id, patch } = updates[i];
    const itemIndex = items.findIndex(item => item.id === id);

    if (itemIndex === -1) {
      results.push({ id, status: 'failure', message: `Item with ID '${id}' not found.` });
      continue;
    }

    const existingItem = items[itemIndex];
    const updatedItem: Item = {
      ...existingItem,
      ...patch,
      updatedAt: new Date().toISOString(), // Always update timestamp on patch
    };

    // Simulate a specific business logic failure (e.g., cannot change status to 'pending' if already 'active')
    if (existingItem.status === 'active' && patch.status === 'pending') {
      results.push({ id, status: 'failure', message: `Cannot change status from 'active' to 'pending'.` });
      continue;
    }

    // If all checks pass, stage the change
    changesToApply.push({ index: itemIndex, updatedItem });
    results.push({ id, status: 'success', data: updatedItem }); // Tentatively mark as success
  }

  // Phase 2: Apply changes (simulated transaction commit)
  // This ensures that if any critical error happened during preparation,
  // or if we wanted a full rollback on *any* item failure, we could do it here.
  // For "per-item success/failure", we apply only the successful ones.
  for (const change of changesToApply) {
    // Find the corresponding result entry to update its data
    const resultEntry = results.find(r => r.id === change.updatedItem.id);
    if (resultEntry && resultEntry.status === 'success') {
      items[change.index] = change.updatedItem;
      resultEntry.data = items[change.index]; // Ensure the returned data is the committed data
    }
  }

  // For items that were marked as failure during preparation, ensure their status is 'failure'
  // and data is not present. This is already handled by how `results` is built.

  return results;
};

/**
 * Retrieves all items.
 */
export const getAllItems = async (): Promise<Item[]> => {
  if (simulateDbError) {
    console.error('Simulating a critical database error during fetch.');
    throw new Error('Database connection lost during fetch.');
  }
  return [...items]; // Return a copy to prevent external modification
};
